class Solution {
public:
    vector<int> sequentialDigits(int low, int high) {
        vector<int> res;
        for (int k = 2; k <= 9; ++k) {
            for (int s = 1; s <= 10 - k; ++s) {
                int num = 0;
                for (int i = 0; i < k; ++i) {
                    num = num * 10 + (s + i);
                }
                if (num >= low && num <= high) {
                    res.push_back(num);
                }
            }
        }
        return res;
    }
};

